  String toString() => '[$precedenceLevel] $pattern';
}

// ---------------------------------------------------------------------------
// Convenience extensions for defining precedence in Dart code
// ---------------------------------------------------------------------------

/// Extension to easily attach precedence levels to patterns.
///
/// Usage:
/// ```dart
/// expr = Rule('expr', () {
///   return Token(ExactToken(49)).atLevel(11) |
///       (Call(expr) >> Token(ExactToken(43)) >> Call(expr)).atLevel(6) |
///       (Call(expr) >> Token(ExactToken(42)) >> Call(expr)).atLevel(7);
/// });
/// ```
extension PrecedenceExtension on Pattern {
  /// Wrap this pattern with an explicit precedence level.
  ///
  /// The precedence level determines which alternatives can match when
  /// a rule is called with a minPrecedenceLevel constraint.
  ///
  /// Example:
  /// - `11` - highest precedence (primary expressions, atoms)
  /// - `7` - medium precedence (multiplication, division)
  /// - `6` - lower precedence (addition, subtraction)
  /// - `1` - lowest precedence (assignment-like operators)
  Pattern atLevel(int precedenceLevel) {
    return PrecedenceLabeledPattern(precedenceLevel, this);
  }

  /// Alias for [atLevel]. Wrap this pattern with an explicit precedence level.
  Pattern withPrecedence(int precedenceLevel) {
    return atLevel(precedenceLevel);
  }
}

// --- $filename ---
/// Grammar definition and building


typedef GrammarBuilder = Pattern Function();

class Grammar with _GrammarMixin implements GrammarInterface {
  final List<Rule> rules = [];
  late final RuleCall startCall;
  Map<Pattern, List<Pattern>>? transitions;
  StateMachine? _stateMachine;

  /// Maps symbol IDs back to patterns for this grammar
  @override
  final Map<String, Pattern> symbolRegistry = {};

  /// Counter for assigning symbol IDs within this grammar
  int _symbolCounter = 0;

  Grammar(GrammarBuilder builder) {
    try {
      final result = builder();
      if (result is RuleCall) {
        finalize(result);
      } else if (result is Call) {
        // Convert Call to RuleCall for grammar entry point
        finalize(result.rule.call());
      } else if (result is Rule) {
        // Convert Rule to RuleCall for grammar entry point
        finalize(result.call());
      } else {
        throw TypeError();
      }
    } catch (e) {
      if (e is TypeError) {
        throw GrammarError('the main pattern must be a rule call');
      }
      rethrow;
    }
  }

  void finalize(RuleCall start) {
    startCall = start.consume() as RuleCall;

    // Discover all rules referenced from the start call
    final discoveredRules = <Rule>{startCall.rule};
    final toProcess = <Rule>{startCall.rule};

    // Recursively discover rules by examining their bodies
    while (toProcess.isNotEmpty) {
      final rule = toProcess.first;
      toProcess.remove(rule);

      // Now safe to call body() since rule is registered
      final body = rule.body();
      final referencedRules = <Rule>{};
      body.collectRules(referencedRules);

      for (final ref in referencedRules) {
        if (!discoveredRules.contains(ref)) {
          discoveredRules.add(ref);
          toProcess.add(ref);
        }
      }
    }

    rules.addAll(discoveredRules);

    // Discover and assign symbol IDs to all patterns used in this grammar
    _assignPatternSymbols();

    _computeEmpty();
    _computeTransitions();
  }

  /// Discovers all patterns in the grammar and assigns them symbol IDs
  void _assignPatternSymbols() {
    final allPatterns = <Pattern>{};

    // Collect all patterns from the grammar's rules, including the rules themselves
    for (final rule in rules) {
      allPatterns.add(rule); // Add the rule itself
      _collectPatternsFromRule(rule, allPatterns);
    }

    // Assign symbol IDs to each pattern in discovery order
    for (final pattern in allPatterns) {
      if (pattern.symbolId == null) {
        final symbolId = 'S${_symbolCounter++}';
        pattern.assignSymbolId(symbolId);
        symbolRegistry[symbolId] = pattern;
      }
    }
  }

  /// Recursively collects all patterns used in a rule's body
  void _collectPatternsFromRule(Rule rule, Set<Pattern> patterns) {
    final body = rule.body();
    _collectPatternsFromPattern(body, patterns);
  }

  /// Recursively collects patterns from a pattern structure
  void _collectPatternsFromPattern(Pattern pattern, Set<Pattern> patterns) {
    if (patterns.contains(pattern)) return; // Avoid cycles
    patterns.add(pattern);

    switch (pattern) {
      case Seq seq:
        _collectPatternsFromPattern(seq.left, patterns);
        _collectPatternsFromPattern(seq.right, patterns);
      case Alt alt:
        _collectPatternsFromPattern(alt.left, patterns);
        _collectPatternsFromPattern(alt.right, patterns);
      case Conj conj:
        _collectPatternsFromPattern(conj.left, patterns);
        _collectPatternsFromPattern(conj.right, patterns);
      case Plus plus:
        _collectPatternsFromPattern(plus.child, patterns);
      case Star star:
        _collectPatternsFromPattern(star.child, patterns);
      case And and:
        _collectPatternsFromPattern(and.pattern, patterns);
      case Not not:
        _collectPatternsFromPattern(not.pattern, patterns);
      case Action action:
        _collectPatternsFromPattern(action.child, patterns);
      case PrecedenceLabeledPattern plp:
        _collectPatternsFromPattern(plp.pattern, patterns);
      default:
        // Token, Marker, Eps, Rule, RuleCall, Call - these are terminals
        break;
    }
  }

  StateMachine get stateMachine {
    _stateMachine ??= StateMachine(this);
    return _stateMachine!;
  }

  @override
  bool isEmpty() => startCall.rule.body().empty();

  // DSL methods
  Token anytoken() => Token(const AnyToken());

  Token token(int codepoint) => Token(ExactToken(codepoint));

  Token tokenRange(int start, int end) {
    if (start < 0 || end < 0) {
      throw GrammarError('only positive code points supported in range');
    }
    return Token(RangeToken(start, end));
  }

  Pattern str(String text) {
    final codepoints = text.codeUnits;
    Pattern result = token(codepoints[0]);
    for (int i = 1; i < codepoints.length; i++) {
      result = result >> token(codepoints[i]);
    }
    return result;
  }

  /// Convenience method for creating a keyword pattern with semantic action.
  /// Transforms the string into a sequence of tokens and wraps with the callback.
  ///
  /// Example:
  /// ```dart
  /// final ifKeyword = grammar.keyword<TokenType>('if', (span, _) => TokenType.IF);
  /// ```
  Action<T> keyword<T>(String text, T Function(String span, List<dynamic> _) action) {
    return str(text).withAction<T>(action);
  }

  /// Convenience method for creating a string pattern that captures the matched text.
  /// Transforms the string into a sequence of tokens and wraps with a capture action.
  ///
  /// Example:
  /// ```dart
  /// final identifier = grammar.literal('hello');
  /// ```
  Action<String> literal(String text) {
    return str(text).withAction<String>((span, _) => span);
  }

  Pattern strRange(IntRange range) {
    if (range.start < 0 || range.end < 0) {
      throw GrammarError('only positive code points supported in range');
    }
    return Token(RangeToken(range.start, range.end));
  }

  Pattern inv(Pattern pattern) => pattern.invert();

  Eps eps() => Eps();

  Marker mark(String name) => Marker(name);

  Alt sepBy(Pattern p, Pattern sep) => sepBy1(p, sep).maybe();

  Seq sepBy1(Pattern p, Pattern sep) => p >> (sep >> p).star();

  Alt endBy(Pattern p, Pattern sep) => endBy1(p, sep).maybe();

  Plus endBy1(Pattern p, Pattern sep) => (p >> sep).plus();

  Rule defRule(String name, Pattern Function() builder) {
    final rule = Rule(name, builder);
    rules.add(rule);
    return rule;
  }

  void _computeEmpty() {
    final emptyRules = <Rule>{};

    bool changed;
    do {
      final sizeBefore = emptyRules.length;

      // Only process rules that are in the explicit rules list
      for (final rule in rules) {
        try {
          if (rule.calculateEmpty(emptyRules)) {
            emptyRules.add(rule);
          }
        } catch (e) {
          // Skip rules that can't be computed yet
        }
      }

      changed = emptyRules.length != sizeBefore;
    } while (changed);
  }

  void _computeTransitions() {
    transitions = {};

    for (final rule in rules) {
      rule.body().eachPair((a, b) {
        transitions![a] ??= [];
        transitions![a]!.add(b);
      });

      for (final lst in rule.body().lastSet()) {
        transitions![lst] ??= [];
        transitions![lst]!.add(rule);
      }

      if (!rule.body().empty() && rule.body().isStatic()) {
        throw GrammarError('rule $rule contains markers in empty position');
      }
    }

    // Use a marker Pattern for the success node
    final successMarker = Marker('__start__');
    transitions![startCall] ??= [];
    transitions![startCall]!.add(successMarker);
  }
}

/// Mixin for Grammar interface
mixin _GrammarMixin {
  RuleCall get startCall;
  List<Rule> get rules;
  bool isEmpty();
}

// Extension for Range syntax
extension IntRangeExtension on int {
  IntRange operator *(int other) => IntRange(this, other);
}

class IntRange {
  final int start;
  final int end;

  IntRange(this.start, this.end);
}

// --- $filename ---
/// State machine compilation from grammars


// Grammar interface to avoid circular import
abstract class GrammarInterface {
  /// Maps symbol IDs back to patterns for this grammar
  Map<String, Pattern> get symbolRegistry;

  RuleCall get startCall;
  List<Rule> get rules;
  bool isEmpty();
}

// Action types for state machine
sealed class StateAction {
  const StateAction();
}

class MarkAction implements StateAction {
  final String name;
  final State nextState;

  const MarkAction(this.name, this.nextState);
}

class TokenAction implements StateAction {
  final Pattern pattern;
  final State nextState;

  const TokenAction(this.pattern, this.nextState);
}

class CallAction implements StateAction {
  final Rule rule;
  final State returnState;

  const CallAction(this.rule, this.returnState);
}

class ReturnAction implements StateAction {
  final Rule rule;

  const ReturnAction(this.rule);
}

class AcceptAction implements StateAction {
  const AcceptAction();
}

class SemanticAction implements StateAction {
  final Object? Function(String span, List<Object?> childResults) callback;
  final State nextState;
  final Pattern? childPattern;

  const SemanticAction(this.callback, this.nextState, [this.childPattern]);
}

/// Predicate action for lookahead assertions (AND/NOT predicates)
/// Does not consume input - purely a condition check
class PredicateAction implements StateAction {
  // Marker type: true for AND (&), false for NOT (!)
  final bool isAnd;

  // The pattern to check for the predicate
  final Pattern pattern;

  // Next state after successful predicate check
  final State nextState;

  const PredicateAction({
    required this.isAnd,
    required this.pattern,
    required this.nextState,
  });

  @override
  String toString() => isAnd ? 'Predicate(&${pattern})' : 'Predicate(!${pattern})';
}

/// State in the state machine
class State {
  final int id;
  final List<StateAction> actions = [];

  State(this.id);

  @override
  String toString() => 'State($id)';
}

/// The compiled state machine
class StateMachine {
  final GrammarInterface grammar;
  final List<Rule> rules = [];
  final Map<Rule, List<State>> ruleFirst = {};
  List<State>? _cachedStates;
  late final List<State> _initialStates;

  final Map<Object, State> _stateMapping = {};

  StateMachine(this.grammar) {
    _buildStateMachine();
  }

  void _buildStateMachine() {
    final initState = _getOrCreateState(':init');
    _connect(initState, grammar.startCall);

    // Mark the state after start call as accepting
    final startState = _getOrCreateState(grammar.startCall);
    startState.actions.add(const AcceptAction());

    if (grammar.isEmpty()) {
      initState.actions.add(const AcceptAction());
    }

    _initialStates = [initState];

    // Process each rule
    for (final rule in grammar.rules) {
      rules.add(rule);

      final firstState = _getOrCreateState(rule);
      ruleFirst[rule] = [firstState];

      // Connect to first patterns
      for (final fst in rule.body().firstSet()) {
        _connect(firstState, fst);
      }

      // Connect each pair
      rule.body().eachPair((a, b) {
        _connect(_getOrCreateState(a), b);
      });

      // Mark states before returns
      for (final lst in rule.body().lastSet()) {
        final state = _getOrCreateState(lst);
        state.actions.add(ReturnAction(rule));
      }
    }
  }

  State _getOrCreateState(Object pattern) {
    if (pattern is String) {
      return _stateMapping.putIfAbsent(
        pattern,
        () => State(_stateMapping.length),
      );
    }
    return _stateMapping.putIfAbsent(
      pattern,
      () => State(_stateMapping.length),
    );
  }

  void _connect(State state, Pattern terminal) {
    if (terminal is Action) {
      // Create a SemanticAction state machine action with the callback
      final nextState = _getOrCreateState(terminal);
      final action = SemanticAction(terminal.callback, nextState, terminal.child);
      state.actions.add(action);
      // Connect the semantic action's next state to the child pattern
      _connect(nextState, terminal.child);
    } else if (terminal is RuleCall) {
      final returnState = _getOrCreateState(terminal);
      final action = CallAction(terminal.rule, returnState);
      state.actions.add(action);
    } else if (terminal is Call) {
      final returnState = _getOrCreateState(terminal);
      final action = CallAction(terminal.rule, returnState);
      state.actions.add(action);
    } else if (terminal is And) {
      // Positive lookahead: create predicate action
      final nextState = _getOrCreateState(terminal);
      final action = PredicateAction(isAnd: true, pattern: terminal.pattern, nextState: nextState);
      state.actions.add(action);
    } else if (terminal is Not) {
      // Negative lookahead: create predicate action
      final nextState = _getOrCreateState(terminal);
      final action = PredicateAction(isAnd: false, pattern: terminal.pattern, nextState: nextState);
      state.actions.add(action);
    } else if (terminal is Token || terminal is Conj) {
      final nextState = _getOrCreateState(terminal);
      final action = TokenAction(terminal, nextState);
      state.actions.add(action);
    } else if (terminal is Marker) {
      final nextState = _getOrCreateState(terminal);
      final action = MarkAction(terminal.name, nextState);
      state.actions.add(action);
    } else {
      throw GrammarError('Unknown terminal: ${terminal.runtimeType}');
    }
  }

  List<State> get states {
    _cachedStates ??= _stateMapping.values.toList();
    return _cachedStates!;
  }

  List<State> get initialStates => _initialStates;
}

// --- $filename ---
/// Shared Packed Parse Forest (SPPF) implementation


/// Base class for all forest nodes
sealed class ForestNode {
  final Pattern pattern;
  final int start;
  final int end;

  ForestNode(this.start, this.end, this.pattern);

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ForestNode &&
          runtimeType == other.runtimeType &&
          start == other.start &&
          end == other.end &&
          pattern == other.pattern;

  @override
  int get hashCode => start.hashCode ^ end.hashCode ^ pattern.hashCode;
}

/// Terminal node (matches a token)
class TerminalNode extends ForestNode {
  final int token;

  TerminalNode(super.start, super.end, super.pattern, this.token);

  @override
  bool operator ==(Object other) =>
      identical(this, other) || super == other && other is TerminalNode && token == (other).token;

  @override
  int get hashCode => super.hashCode ^ token.hashCode;

  @override
  String toString() => 'Terminal($token, [$start, $end))';
}

/// Marker node (for named positions / @mark identifiers)
class MarkerNode extends ForestNode {
  final String name;

  MarkerNode(int position, Pattern pattern, this.name) : super(position, position, pattern);

  @override
  bool operator ==(Object other) =>
      identical(this, other) || super == other && other is MarkerNode && name == (other).name;

  @override
  int get hashCode => super.hashCode ^ name.hashCode;

  @override
  String toString() => 'Marker(\$name)[$start]';
}

/// Symbolic node (non-terminal)
class SymbolicNode extends ForestNode {
  final String symbol;
  final List<Family> families = [];

  SymbolicNode(super.start, super.end, super.pattern, this.symbol);

  void addFamily(Family family) {
    if (!families.contains(family)) {
      families.add(family);
    }
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) || super == other && other is SymbolicNode && symbol == (other).symbol;

  @override
  int get hashCode => super.hashCode ^ symbol.hashCode;

  @override
  String toString() => '$symbol[$start:$end]';
}

/// Intermediate node (represents semantic actions on children)
class IntermediateNode extends ForestNode {
  final String description;
  final List<Family> families = [];

  IntermediateNode(super.start, super.end, super.pattern, this.description);

  void addFamily(Family family) {
    if (!families.contains(family)) {
      families.add(family);
    }
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      super == other && other is IntermediateNode && description == (other).description;

  @override
  int get hashCode => super.hashCode ^ description.hashCode;

  @override
  String toString() => 'Intermediate($description, [$start, $end))';
}

/// Family of parse derivations (alternatives)
class Family {
  final List<ForestNode> children;
  final List<Mark> marks;

  Family(this.children, [this.marks = const []]);

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is Family &&
          runtimeType == other.runtimeType &&
          _listEquals(children, (other).children) &&
          _listEquals(marks, (other).marks);

  @override
  int get hashCode =>
      children.fold(0, (h, c) => h ^ c.hashCode) ^ marks.fold(0, (h, m) => h ^ m.hashCode);

  bool _listEquals<T>(List<T> a, List<T> b) {
    if (a.length != b.length) return false;
    for (int i = 0; i < a.length; i++) {
      if (a[i] != b[i]) return false;
    }
    return true;
  }

  @override
  String toString() {
    final childStr = children.join(', ');
    return 'Family([$childStr])';
  }
}

/// Epsilon node (empty parse)
class EpsilonNode extends ForestNode {
  EpsilonNode(int position, Pattern pattern) : super(position, position, pattern);

  @override
  String toString() => 'ε[$start]';
}

/// Forest node manager (deduplicates and caches nodes)
class ForestNodeManager {
  final Map<String, ForestNode> _nodeCache = {};
  final Set<SymbolicNode> _symbolicNodes = {};
  final Set<TerminalNode> _terminalNodes = {};
  final Set<IntermediateNode> _intermediateNodes = {};
  final Set<MarkerNode> _markerNodes = {};

  String _makeCacheKey(String type, int start, int end, Pattern pattern, [String detail = '']) {
    return '$type:$start:$end:${identityHashCode(pattern)}:$detail';
  }

  /// Get or create a terminal node
  TerminalNode terminal(int start, int end, Pattern pattern, int token) {
    final key = _makeCacheKey('term', start, end, pattern, token.toString());
    if (_nodeCache[key] case TerminalNode node) {
      return node;
    }
    final node = TerminalNode(start, end, pattern, token);
    _nodeCache[key] = node;
    _terminalNodes.add(node);
    return node;
  }

  /// Get or create a symbolic node
  SymbolicNode symbolic(int start, int end, Pattern rule) {
    final key = _makeCacheKey('sym', start, end, rule, rule.symbolId!);
    if (_nodeCache[key] case SymbolicNode node) {
      return node;
    }
    final node = SymbolicNode(start, end, rule, rule.symbolId!);
    _nodeCache[key] = node;
    _symbolicNodes.add(node);
    return node;
  }

  /// Get or create an intermediate node
  IntermediateNode intermediate(int start, int end, Pattern pattern, String description) {
    final key = _makeCacheKey('inter', start, end, pattern, description);
    if (_nodeCache[key] case IntermediateNode node) {
      return node;
    }
    final node = IntermediateNode(start, end, pattern, description);
    _nodeCache[key] = node;
    _intermediateNodes.add(node);
    return node;
  }

  /// Get or create an epsilon node
  EpsilonNode epsilon(int position, Pattern pattern) {
    final key = _makeCacheKey('eps', position, position, pattern);
    if (_nodeCache[key] case EpsilonNode node) {
      return node;
    }
    final node = EpsilonNode(position, pattern);
    _nodeCache[key] = node;
    return node;
  }

  /// Get or create a marker node
  MarkerNode marker(int position, Marker pattern) {
    final key = _makeCacheKey('mark', position, position, pattern, pattern.name);
    if (_nodeCache[key] case MarkerNode node) {
      return node;
    }
    final node = MarkerNode(position, pattern, pattern.name);
    _nodeCache[key] = node;
    _markerNodes.add(node);
    return node;
  }

  Set<SymbolicNode> get symbolicNodes => _symbolicNodes;
  Set<TerminalNode> get terminalNodes => _terminalNodes;
  Set<IntermediateNode> get intermediateNodes => _intermediateNodes;
  Set<MarkerNode> get markerNodes => _markerNodes;
}

/// Parse forest representation
class ParseForest {
  final ForestNodeManager nodeManager;
  final SymbolicNode root;
  final List<Mark> marks;

  ParseForest(this.nodeManager, this.root, this.marks);

  /// Count total nodes in the forest
  int countNodes() {
    final visited = <ForestNode>{};
    _countNodesRecursive(root, visited);
    return visited.length;
  }

  void _countNodesRecursive(ForestNode node, Set<ForestNode> visited) {
    if (visited.contains(node)) return;
    visited.add(node);

    if (node is SymbolicNode) {
      for (final family in node.families) {
        for (final child in family.children) {
          _countNodesRecursive(child, visited);
        }
      }
    } else if (node is IntermediateNode) {
      for (final family in node.families) {
        for (final child in family.children) {
          _countNodesRecursive(child, visited);
        }
      }
    }
  }

  /// Count total families (derivations) in the forest
  int countFamilies() {
    final visited = <ForestNode>{};
    return _countFamiliesRecursive(root, visited);
  }

  int _countFamiliesRecursive(ForestNode node, Set<ForestNode> visited) {
    if (visited.contains(node)) return 0;
    visited.add(node);

    int count = 0;
    if (node is SymbolicNode) {
      count = node.families.length;
      for (final family in node.families) {
        for (final child in family.children) {
          count += _countFamiliesRecursive(child, visited);
        }
      }
    } else if (node is IntermediateNode) {
      count = node.families.length;
      for (final family in node.families) {
        for (final child in family.children) {
          count += _countFamiliesRecursive(child, visited);
        }
      }
    }
    return count;
  }

  /// Lazily yields all parse trees contained in the forest.
  Iterable<ParseTree> extract() sync* {
    yield* _extractTrees(root);
  }

  Iterable<ParseTree> _extractTrees(ForestNode node) sync* {
    if (node is SymbolicNode) {
      if (node.families.isEmpty) {
        yield ParseTree(node, const []);
        return;
      }
      for (final family in node.families) {
        if (family.children.isEmpty) {
          yield ParseTree(node, const []);
        } else {
          yield* _extractFamilyTrees(node, family);
        }
      }
    } else if (node is IntermediateNode) {
      if (node.families.isEmpty) {
        yield ParseTree(node, const []);
        return;
      }
      for (final family in node.families) {
        if (family.children.isEmpty) {
          yield ParseTree(node, const []);
        } else {
          yield* _extractFamilyTrees(node, family);
        }
      }
    } else {
      yield ParseTree(node, const []);
    }
  }

  /// Lazily yields one [ParseTree] per combination of child subtrees for [family].
  Iterable<ParseTree> _extractFamilyTrees(ForestNode parent, Family family) sync* {
    // Collect sub-iterables for each child position
    final childOptions = family.children.map((child) => _extractTrees(child).toList()).toList();
    // Yield the Cartesian product of the child options as ParseTree nodes
    for (final combination in _cartesianProduct(childOptions)) {
      yield ParseTree(parent, combination);
    }
  }

  /// Lazily yields every combination (one item from each of [lists] in order).
  Iterable<List<ParseTree>> _cartesianProduct(List<List<ParseTree>> lists) sync* {
    if (lists.isEmpty) {
      yield const [];
      return;
    }
    for (final head in lists.first) {
      for (final tail in _cartesianProduct(lists.sublist(1))) {
        yield [head, ...tail];
      }
    }
  }

  @override
  String toString() {
    return 'ParseForest(root=$root, nodes=${countNodes()}, families=${countFamilies()})';
  }
}

/// A single parse tree extracted from the forest
class ParseTree {
  final ForestNode node;
  final List<ParseTree> children;

  ParseTree(this.node, this.children);

  /// Convert to a readable string representation
  String toTreeString([int indent = 0]) {
    final prefix = '  ' * indent;
    final str = '$prefix$node\n';
    return str + children.map((c) => c.toTreeString(indent + 1)).join('');
  }

  String toPrecedenceString(String input) {
    final mapped = children.map((c) => c.toPrecedenceString(input)).join("");
    if (mapped.isEmpty) {
      return input.substring(node.start, node.end);
    }

    return switch (children.length) { > 1 => "($mapped)", 1 => mapped, _ => throw Error() };
  }

  @override
  String toString() => node.toString();
}

// --- $filename ---
/// Binary Subtree Representation (BSR) for compact derivation recording.
///
/// A BSR set is populated *during* parsing. Each entry records that a rule
/// was successfully completed over a specific input span.  The SPPF can then
/// be derived on-demand from these entries rather than from an exhaustive
/// grammar walk.
///
/// Reference: Scott & Johnstone, "GLL Parse-Tree Generation" (2013).



// ---------------------------------------------------------------------------
// Trampoline for CPS-based recursion management
// ---------------------------------------------------------------------------

abstract class _Trampoline<T> {
  T run() {
    _Trampoline<T> current = this;
    while (current is _More<T>) {
      current = current.next();
    }
    return (current as _Done<T>).result;
  }
}

class _More<T> extends _Trampoline<T> {
  final _Trampoline<T> Function() next;
  _More(this.next);
}

class _Done<T> extends _Trampoline<T> {
  final T result;
  _Done(this.result);
}

extension _TrampolineExtensions<T> on _Trampoline<T> {
  _Trampoline<U> then<U>(_Trampoline<U> Function(T) f) {
    if (this is _Done<T>) {
      return f((this as _Done<T>).result);
    }
    return _More<U>(() => (this as _More<T>).next().then(f));
  }
}

/// A single rule-completion entry in the BSR.
///
/// Records that [rule] was successfully parsed over the input span
/// [[leftExtent], [rightExtent]).
typedef BsrEntry = (Pattern rule, int leftExtent, int rightExtent);

extension BsrEntryMethods on BsrEntry {
  Pattern get rule => $1;
  int get leftExtent => $2;
  int get rightExtent => $3;
}

/// The set of all [BsrEntry] instances accumulated during a parse.
///
/// Can be queried to check which rules were proven to match which spans,
/// and can construct an SPPF on demand restricted to proven spans.
class BsrSet {
  final Set<BsrEntry> _entries = {};

  /// Add a rule-completion entry.
  void add(Pattern rule, int leftExtent, int rightExtent) {
    _entries.add((rule, leftExtent, rightExtent));
  }

  /// Returns true if [rule] was proven to match [[left], [right]).
  bool contains(Pattern rule, int left, int right) => _entries.contains((rule, left, right));

  /// Returns all entries for the given rule.
  Iterable<BsrEntry> entriesForRule(Rule rule) => _entries.where((e) => e.rule == rule);

  /// Returns all entries matching a given span (any rule).
  Iterable<BsrEntry> entriesForSpan(int left, int right) =>
      _entries.where((e) => e.leftExtent == left && e.rightExtent == right);

  /// Total number of recorded rule-completion entries.
  int get length => _entries.length;

  /// Build an SPPF rooted at [startRule] over the full input of length
  /// [inputLength], using only spans that are proven in this BSR set.
  ///
  /// Returns null if the start rule has no proven entry for [0, inputLength].
  SymbolicNode? buildSppf(
    Rule startRule,
    String input,
    ForestNodeManager nodeManager,
  ) {
    final memo = <String, SymbolicNode?>{};
    final inProgress = <String, bool>{};
    return _buildNode(startRule, input, 0, input.length, nodeManager, memo, inProgress).run();
  }

  // ---------------------------------------------------------------------------
  // Internal SPPF construction (BSR-guided grammar walk)
  // ---------------------------------------------------------------------------
  _Trampoline<SymbolicNode?> _buildNode(
    Rule rule,
    String input,
    int start,
    int end,
    ForestNodeManager nodeManager,
    Map<String, SymbolicNode?> memo,
    Map<String, bool> inProgress,
  ) {
    // Fast-fail: only build SPPF for spans the BSR proves are reachable.
    if (!contains(rule, start, end)) return _Done(null);

    final key = '${rule.symbolId}:$start:$end';
    if (memo.containsKey(key)) return _Done(memo[key]);
    if (inProgress[key] == true) return _Done(null);

    inProgress[key] = true;
    final symNode = nodeManager.symbolic(start, end, rule);

    return _More(() => _patternNodes(
          rule.body(),
          input,
          start,
          end,
          nodeManager,
          memo,
          inProgress,
          (childNodes) {
            for (final child in childNodes) {
              // Rule nodes now strictly point to 1 child (which may be an IntermediateNode handling the rest)
              symNode.addFamily(Family([child]));
            }

            inProgress[key] = false;
            final result = symNode.families.isNotEmpty ? symNode : null;
            memo[key] = result;
            return _Done(result);
          },
        ));
  }

  _Trampoline<T> _patternNodes<T>(
    Pattern pattern,
    String input,
    int start,
    int end,
    ForestNodeManager nodeManager,
    Map<String, SymbolicNode?> memo,
    Map<String, bool> inProgress,
    _Trampoline<T> Function(List<ForestNode>) continuation,
  ) {
    switch (pattern) {
      case Token():
        if (start + 1 == end && pattern.match(input.codeUnitAt(start))) {
          return continuation([nodeManager.terminal(start, end, pattern, input.codeUnitAt(start))]);
        }
        return continuation([]);
      case Marker():
        return continuation(start == end ? [nodeManager.marker(start, pattern)] : []);
      case Eps():
        return continuation(start == end ? [nodeManager.epsilon(start, pattern)] : []);
      case Alt():
        return _More(() => _patternNodes(
              pattern.left,
              input,
              start,
              end,
              nodeManager,
              memo,
              inProgress,
              (leftNodes) => _More(() => _patternNodes(
                    pattern.right,
                    input,
                    start,
                    end,
                    nodeManager,
                    memo,
                    inProgress,
                    (rightNodes) => continuation([...leftNodes, ...rightNodes]),
                  )),
            ));
      case Seq():
        IntermediateNode? seqNode;

        _Trampoline<T> loop(int mid) {
          if (mid > end) return continuation(seqNode != null ? [seqNode!] : []);

          return _More(() => _patternNodes(
                pattern.left,
                input,
                start,
                mid,
                nodeManager,
                memo,
                inProgress,
                (leftNodes) {
                  if (leftNodes.isEmpty) return _More(() => loop(mid + 1));

                  return _More(() => _patternNodes(
                        pattern.right,
                        input,
                        mid,
                        end,
                        nodeManager,
                        memo,
                        inProgress,
                        (rightNodes) {
                          if (rightNodes.isNotEmpty) {
                            // Hoisted intermediate creation: strictly packed and binarised
                            seqNode ??= nodeManager.intermediate(start, end, pattern, 'Seq');
                            for (final l in leftNodes) {
                              for (final r in rightNodes) {
                                seqNode!.addFamily(Family([l, r]));
                              }
                            }
                          }
                          return _More(() => loop(mid + 1));
                        },
                      ));
                },
              ));
        }

        return _More(() => loop(start));
      case Conj():
        if (start + 1 == end &&
            pattern.left.match(input.codeUnitAt(start)) &&
            pattern.right.match(input.codeUnitAt(start))) {
          final termNode = nodeManager.terminal(start, end, pattern, input.codeUnitAt(start));
          return continuation([termNode]);
        }
        return continuation([]);
      case Plus():
        IntermediateNode? plusNode;

        _Trampoline<T> loop(int mid) {
          if (mid > end) {
            return _More(() => _patternNodes(
                  pattern.child,
                  input,
                  start,
                  end,
                  nodeManager,
                  memo,
                  inProgress,
                  (singleNodes) {
                    if (singleNodes.isNotEmpty) {
                      plusNode ??= nodeManager.intermediate(start, end, pattern, 'Plus');
                      for (final s in singleNodes) {
                        plusNode!.addFamily(Family([s]));
                      }
                    }
                    return continuation(plusNode != null ? [plusNode!] : []);
                  },
                ));
          }

          return _More(() => _patternNodes(
                pattern.child,
                input,
                start,
                mid,
                nodeManager,
                memo,
                inProgress,
                (headNodes) {
                  if (headNodes.isEmpty) return _More(() => loop(mid + 1));

                  return _More(() => _patternNodes(
                        pattern,
                        input,
                        mid,
                        end,
                        nodeManager,
                        memo,
                        inProgress,
                        (tailNodes) {
                          if (tailNodes.isNotEmpty) {
                            plusNode ??= nodeManager.intermediate(start, end, pattern, 'Plus');
                            for (final h in headNodes) {
                              for (final t in tailNodes) {
                                plusNode!.addFamily(Family([h, t]));
                              }
                            }
                          }
                          return _More(() => loop(mid + 1));
                        },
                      ));
                },
              ));
        }

        return _More(() => loop(start + 1));
      case Star():
        IntermediateNode? starNode;

        _Trampoline<T> loop(int mid) {
          if (mid > end) {
            if (start == end) {
              starNode ??= nodeManager.intermediate(start, end, pattern, 'Star');
              starNode!.addFamily(Family([nodeManager.epsilon(start, pattern)]));
            }
            return continuation(starNode != null ? [starNode!] : []);
          }

          return _More(() => _patternNodes(
                pattern.child,
                input,
                start,
                mid,
                nodeManager,
                memo,
                inProgress,
                (headNodes) {
                  if (headNodes.isEmpty) return _More(() => loop(mid + 1));

                  return _More(() => _patternNodes(
                        pattern,
                        input,
                        mid,
                        end,
                        nodeManager,
                        memo,
                        inProgress,
                        (tailNodes) {
                          if (tailNodes.isNotEmpty) {
                            starNode ??= nodeManager.intermediate(start, end, pattern, 'Star');
                            for (final h in headNodes) {
                              for (final t in tailNodes) {
                                starNode!.addFamily(Family([h, t]));
                              }
                            }
                          }
                          return _More(() => loop(mid + 1));
                        },
                      ));
                },
              ));
        }

        return _More(() => loop(start + 1));
      case And() || Not():
        if (start == end) {
          return continuation([nodeManager.epsilon(start, pattern)]);
        }
        return continuation([]);
      case Rule():
        return _More(() => _patternNodes(
              pattern.body(),
              input,
              start,
              end,
              nodeManager,
              memo,
              inProgress,
              continuation,
            ));
      case RuleCall(:var rule) || Call(:var rule):
        return _More(() => _buildNode(rule, input, start, end, nodeManager, memo, inProgress)
            .then((child) => continuation(child != null ? [child] : [])));
      case Action<dynamic>():
        return _More(() => _patternNodes(
              pattern.child,
              input,
              start,
              end,
              nodeManager,
              memo,
              inProgress,
              (childNodes) {
                if (childNodes.isEmpty) return continuation([]);

                final node = nodeManager.intermediate(start, end, pattern, 'Action<T>');
                for (final child in childNodes) {
                  node.addFamily(Family([child]));
                }
                return continuation([node]);
              },
            ));
      case PrecedenceLabeledPattern():
        return _More(() => _patternNodes(
              pattern.pattern,
              input,
              start,
              end,
              nodeManager,
              memo,
              inProgress,
              continuation,
            ));
    }
  }

  @override
  String toString() => 'BsrSet(${_entries.length} entries)';
}

// ---------------------------------------------------------------------------
// Parse outcome types for BSR-based parsing
// ---------------------------------------------------------------------------

/// Sealed result type for [SMParser.parseToBsr].
sealed class BsrParseOutcome {}

/// Returned when BSR parsing fails.
final class BsrParseError implements BsrParseOutcome, Exception {
  final int position;

  const BsrParseError(this.position);

  @override
  String toString() => 'BsrParseError at position $position';
}

/// Returned when BSR parsing succeeds. Contains the [BsrSet] of proven spans.
final class BsrParseSuccess implements BsrParseOutcome {
  final BsrSet bsrSet;
  final List<Mark> marks;

  const BsrParseSuccess(this.bsrSet, this.marks);

  @override
  String toString() => 'BsrParseSuccess($bsrSet)';
}

// --- $filename ---
/// State machine-based parser implementation



// ---------------------------------------------------------------------------
// Parse result types — sealed hierarchy replaces dynamic return values
// ---------------------------------------------------------------------------

/// Sealed result type returned by [SMParser.parse] and [SMParser.parseWithForest].
sealed class ParseOutcome<T> {}

/// Returned when parsing fails.
final class ParseError<T> extends ParseOutcome<T> implements Exception {
  final int position;

  ParseError(this.position);

  @override
  String toString() => 'ParseError at position $position';
}

/// Returned when parsing succeeds (marks-based parse).
final class ParseSuccess<T> extends ParseOutcome<T> {
  final ParserResult result;

  ParseSuccess(this.result);
}

/// Returned when parsing succeeds with a full parse forest.
final class ParseForestSuccess<T> extends ParseOutcome<T> {
  final ParseForest forest;

  ParseForestSuccess(this.forest);

  @override
  String toString() => 'ParseForestSuccess(forest=$forest)';
}

// ---------------------------------------------------------------------------

class ParserResult {
  final List<Mark> _rawMarks;

  ParserResult(this._rawMarks);

  List<String> get marks {
    final result = <String>[];
    String? currentStringMark;

    for (final mark in _rawMarks) {
      if (mark is NamedMark) {
        if (currentStringMark != null) {
          result.add(currentStringMark);
          currentStringMark = null;
        }
        result.add(mark.name);
      } else if (mark is StringMark) {
        currentStringMark = (currentStringMark ?? '') + mark.value;
      }
    }

    if (currentStringMark != null) {
      result.add(currentStringMark);
    }

    return result;
  }

  List<List<Object?>> toList() => _rawMarks.map((m) {
        if (m is NamedMark) return m.toList();
        if (m is StringMark) return m.toList();
        return [];
      }).toList();
}

/// Represents a single parse tree derivation
class ParseDerivation {
  final String symbol;
  final int start;
  final int end;
  final List<ParseDerivation> children;

  const ParseDerivation(this.symbol, this.start, this.end, this.children);

  /// Get substring that this derivation matched
  String getMatchedText(String input) {
    if (input.isEmpty || start >= input.length) {
      return '';
    }
    final actualEnd = end > input.length ? input.length : end;
    return input.substring(start, actualEnd);
  }

  /// Convert to flat tree string showing matched content and structure
  /// Example: for input "sss" with grammar S=s|SS|SSS might show (s(ss))
  String toTreeString(String? input) {
    if (children.isEmpty) {
      // Leaf node - show the matched text if input provided, otherwise just span
      if (input != null) {
        return getMatchedText(input);
      }
      return input == null ? '[$start:$end]' : '${input.substring(start, end)}';
    }
    if (children.length == 1) {
      return children.single.toTreeString(input);
    }
    // Parens showing children structure with their matched content
    final childStr = children.map((c) => c.toTreeString(input)).join('');
    return '($childStr)';
  }

  Object? getSimplified(String input) {
    if (children.isEmpty) {
      return input.substring(start, end);
    }

    if (children.length == 1) {
      return children.single.getSimplified(input);
    }

    return children.map((c) => c.getSimplified(input)).toList();
  }

  /// Pretty print the parse tree
  @override
  String toString() => '$symbol[$start:$end]';
}

/// Represents a parse tree with its evaluated semantic value
class ParseDerivationWithValue<T> {
  final ParseDerivation tree;
  final T value;
  final GrammarInterface? grammar;

  ParseDerivationWithValue(this.tree, this.value, {this.grammar});

  /// Get substring that this derivation matched
  String getMatchedText(String input) => tree.getMatchedText(input);

  /// Get the tree's symbol (as a String ID)
  String get symbol => tree.symbol;

  /// Get the tree's pattern object from the registry (uses grammar context if available)
  Pattern? get pattern {
    if (grammar case var grammar?) {
      return grammar.symbolRegistry[tree.symbol];
    }
    return null;
  }

  /// Get the tree's span
  int get start => tree.start;
  int get end => tree.end;

  /// Get the tree's children
  List<ParseDerivation> get children => tree.children;

  @override
  String toString() => '$symbol[$start:$end]=$value';
}

// ---------------------------------------------------------------------------
// Predicate lookahead buffer — supports unbounded lookahead with buffering
// ---------------------------------------------------------------------------

/// Manages lookahead for predicates without exposing full input during parsing.
/// Dynamically accumulates characters in a buffer and caches predicate results.
/// Supports both synchronous (pre-loaded input) and async (streaming) usage.
class PredicateLookaheadBuffer {
  final List<int> _buffer = []; // Dynamic character buffer
  final Map<(int, String), bool> _predicateCache = {};

  /// Initialize buffer with a complete string (for synchronous parsing)
  void initializeFromString(String input) {
    _buffer.clear();
    _buffer.addAll(input.codeUnits);
  }

  /// Add a single character to the buffer (for streaming)
  void addCodeUnit(int codeUnit) {
    _buffer.add(codeUnit);
  }

  /// Add multiple characters to the buffer
  void addCodeUnits(List<int> codeUnits) {
    _buffer.addAll(codeUnits);
  }

  /// Get a character at position, or -1 if out of bounds
  int codeUnitAt(int position) {
    if (position < 0 || position >= _buffer.length) return -1;
    return _buffer[position];
  }

  /// Check if there are at least [length] characters available from [position]
  bool hasCharsAt(int position, int length) {
    return position >= 0 && position + length <= _buffer.length;
  }

  /// Get substring from [start] to [end], or empty string if out of bounds
  String getSubstring(int start, int end) {
    if (start < 0 || end > _buffer.length || start > end) return '';
    // Convert codeUnits to string
    return String.fromCharCodes(_buffer.sublist(start, end));
  }

  /// Total buffered characters
  int get length => _buffer.length;

  /// Clear the buffer (useful for resetting state)
  void clear() {
    _buffer.clear();
    _predicateCache.clear();
  }

  /// Cache a predicate result to avoid recomputation
  bool cachedPredicateCheck(int position, String patternKey, bool Function() evaluate) {
    final key = (position, patternKey);
    return _predicateCache.putIfAbsent(key, evaluate);
  }

  /// Clear the predicate cache (if needed)
  void clearCache() => _predicateCache.clear();
}

class SMParser {
  final StateMachine stateMachine;
  final GrammarInterface grammar;
  late final List<Frame> _initialFrames;
  late PredicateLookaheadBuffer _predicateBuffer;

  SMParser(GrammarInterface grammar)
      : stateMachine = StateMachine(grammar),
        grammar = grammar {
    const initialContext = Context(RootCallerKey(), null);
    final initialFrame = Frame(initialContext);
    initialFrame.nextStates.addAll(stateMachine.initialStates);
    _initialFrames = [initialFrame];
    // Initialize buffer (can be reused across parses with clear())
    _predicateBuffer = PredicateLookaheadBuffer();
  }

  bool recognize(String input) {
    _predicateBuffer.initializeFromString(input);
    var frames = _initialFrames;
    int position = 0;

    for (final codepoint in input.codeUnits) {
      final stepResult = _processToken(codepoint, position, frames);
      frames = stepResult.nextFrames;
      if (frames.isEmpty) return false;
      position++;
    }

    final lastStep = _processToken(null, position, frames);
    return lastStep.accept;
  }

  ParseOutcome<T> parse<T>(String input) {
    _predicateBuffer.initializeFromString(input);
    var frames = _initialFrames;
    int position = 0;

    for (final codepoint in input.codeUnits) {
      final stepResult = _processToken(codepoint, position, frames);
      frames = stepResult.nextFrames;
      if (frames.isEmpty) {
        return ParseError<T>(position);
      }
      position++;
    }

    final lastStep = _processToken(null, position, frames);

    if (lastStep.accept) {
      return ParseSuccess<T>(ParserResult(lastStep.marks));
    } else {
      return ParseError<T>(position);
    }
  }

  /// Parse with forest extraction enabled.
  ///
  /// Internally uses BSR (Binarised Shared Representation) recorded during
  /// parsing to restrict the SPPF construction to spans proven reachable by
  /// the parser, rather than exhaustively searching the whole grammar.
  ParseOutcome<T> parseWithForest<T>(String input) {
    Stopwatch watch = Stopwatch()..start();
    _predicateBuffer.initializeFromString(input);
    final bsrOutcome = parseToBsr(input);
    if (bsrOutcome is BsrParseError) {
      return ParseError<T>(bsrOutcome.position);
    }
    watch..stop();
    print("Finished processing BSR in ${watch.elapsedMicroseconds}us");

    final bsrSuccess = bsrOutcome as BsrParseSuccess;
    final bsrSet = bsrSuccess.bsrSet;
    final startRule = stateMachine.grammar.startCall.rule;
    final nodeManager = ForestNodeManager();
    final root = bsrSet.buildSppf(startRule, input, nodeManager);
    final effectiveRoot = root ?? nodeManager.symbolic(0, input.length, startRule);
    final forest = ParseForest(nodeManager, effectiveRoot, []);
    return ParseForestSuccess<T>(forest);
  }

  /// Parse a stream of input chunks with forest extraction.
  ///
  /// Processes input incrementally as chunks arrive without buffering the entire
  /// stream in memory. Uses a bounded sliding-window buffer for predicate lookahead
  /// (default 1MB). Suitable for streaming large files.
  ///
  /// WARNING: If the grammar has predicates that require lookahead beyond the
  /// buffer window, results may be incorrect. Adjust [lookaheadWindowSize] if needed.
  Future<ParseOutcome<T>> parseWithForestAsync<T>(
    Stream<String> input, {
    int lookaheadWindowSize = 1048576,
  }) {
    _predicateBuffer.clear();

    final completer = Completer<ParseOutcome<T>>();
    var frames = _initialFrames;
    int globalPosition = 0;

    // Bounded buffer for lookahead: prevents unbounded memory growth
    final lookaheadWindow = <int>[];

    // Keep all input for a second pass to get marks (required for correct SPPF construction)
    final allInput = <int>[];

    // BSR recording happens as we parse
    final bsr = BsrSet();

    input.listen(
      (chunk) {
        try {
          // Feed chunk data into the parser token-by-token
          for (final codeUnit in chunk.codeUnits) {
            // Store for second pass
            allInput.add(codeUnit);

            // Maintain bounded window: keep only recent data for lookahead
            lookaheadWindow.add(codeUnit);
            if (lookaheadWindow.length > lookaheadWindowSize) {
              lookaheadWindow.removeAt(0);
            }

            // Update the predicate buffer for this token
            _predicateBuffer._buffer.clear();
            _predicateBuffer._buffer.addAll(lookaheadWindow);

            // Process this token with BSR recording
            final stepResult = _processToken(codeUnit, globalPosition, frames, bsr: bsr);
            frames = stepResult.nextFrames;

            // If parsing fails, complete with error
            if (frames.isEmpty) {
              completer.complete(ParseError<T>(globalPosition));
              return;
            }

            globalPosition++;
          }
        } catch (e) {
          completer.completeError(e);
        }
      },
      onError: (error) {
        if (!completer.isCompleted) {
          completer.completeError(error);
        }
      },
      onDone: () {
        // Defer finalization to avoid blocking
        Future.microtask(() {
          try {
            if (completer.isCompleted) return;

            // Process end-of-stream token
            final lastStep = _processToken(null, globalPosition, frames, bsr: bsr);

            if (lastStep.accept) {
              // Now do a second pass over the buffered input to get marks
              // (matches the sync algorithm's approach)
              _predicateBuffer.initializeFromString(String.fromCharCodes(allInput));
              var marksFrames = _initialFrames;
              for (int i = 0; i < allInput.length; i++) {
                final stepResult = _processToken(allInput[i], i, marksFrames, bsr: null);
                marksFrames = stepResult.nextFrames;
              }
              final marksStep = _processToken(null, allInput.length, marksFrames, bsr: null);

              // Build SPPF from the recorded BSR
              final startRule = stateMachine.grammar.startCall.rule;
              final nodeManager = ForestNodeManager();
              final fullInput = String.fromCharCodes(allInput);
              final root = bsr.buildSppf(startRule, fullInput, nodeManager);
              final effectiveRoot = root ?? nodeManager.symbolic(0, globalPosition, startRule);
              final forest = ParseForest(nodeManager, effectiveRoot, marksStep.marks);
              completer.complete(ParseForestSuccess<T>(forest));
            } else {
              completer.complete(ParseError<T>(globalPosition));
            }
          } catch (e) {
            if (!completer.isCompleted) {
              completer.completeError(e);
            }
          }
        });
      },
    );

    return completer.future;
  }

  /// Parse and return the BSR set of all proven rule-completion spans.
  ///
  /// Returns [BsrParseSuccess] with the [BsrSet] on success, or
  /// [BsrParseError] if the input does not conform to the grammar.
  BsrParseOutcome parseToBsr(String input) {
    _predicateBuffer.initializeFromString(input);
    final bsr = BsrSet();
    var frames = _initialFrames;
    int position = 0;

    for (final codepoint in input.codeUnits) {
      final stepResult = _processToken(
        codepoint,
        position,
        frames,
        input: input,
        bsr: bsr,
      );
      frames = stepResult.nextFrames;
      if (frames.isEmpty) {
        return BsrParseError(position);
      }
      position++;
    }

    final lastStep = _processToken(null, position, frames, input: input, bsr: bsr);

    if (lastStep.accept) {
      return BsrParseSuccess(bsr, lastStep.marks);
    } else {
      return BsrParseError(position);
    }
  }

  /// Count all possible parse trees without building them
  int countAllParses(String input) {
    final startRule = stateMachine.grammar.startCall.rule;
    return _countDerivations(startRule, input, 0, input.length, {}, {});
  }

  /// Enumerate all possible parse trees lazily, yielding each as a [ParseDerivation].
  Iterable<ParseDerivation> enumerateAllParses(String input) {
    final startRule = stateMachine.grammar.startCall.rule;
    return _enumerateDerivations(startRule, input, 0, input.length, {}, {});
  }

  /// Enumerate all possible parse trees with evaluated semantic values.
  /// Actions are executed bottom-up with child results.
  Iterable<ParseDerivationWithValue<dynamic>> enumerateAllParsesWithResults(String input) sync* {
    for (final derivation in enumerateAllParses(input)) {
      final value = evaluateParseDerivation(derivation, input);
      yield ParseDerivationWithValue(derivation, value, grammar: grammar);
    }
  }

  /// Extract all parse trees from a [ParseForest] with evaluated semantic actions.
  /// This provides a forest-based alternative to [enumerateAllParsesWithResults],
  /// yielding [ParseDerivationWithValue] results with top-level semantic values.
  ///
  /// The forest should come from [parseWithForest] on matching input.
  Iterable<ParseDerivationWithValue<dynamic>> enumerateForestWithResults(
    ParseForestSuccess forest,
    String input,
  ) sync* {
    for (final tree in forest.forest.extract()) {
      final derivation = parseTreeToDerivation(tree, input);
      final value = evaluateParseDerivation(derivation, input);
      yield ParseDerivationWithValue(derivation, value, grammar: grammar);
    }
  }

  /// Convert a [ParseTree] (forest representation) to a [ParseDerivation] (enumeration representation).
  static ParseDerivation parseTreeToDerivation(ParseTree tree, String input) {
    final childDerivations = tree.children //
        .map((c) => parseTreeToDerivation(c, input))
        .toList();

    return ParseDerivation(
      tree.node.pattern.symbolId!,
      tree.node.start,
      tree.node.end,
      childDerivations,
    );
  }

  int _countDerivations(Rule rule, String input, int start, int end, Map<String, int> memo,
      Map<String, bool> inProgress) {
    final key = '${rule.name}:$start:$end';

    if (memo.containsKey(key)) {
      return memo[key]!;
    }

    // Check for cycle - if we're already processing this rule at this span, break the cycle
    if (inProgress[key] == true) {
      return 0; // Prevent infinite recursion on identity rules
    }

    if (start == end) {
      try {
        final isEmpty = rule.body().empty();
        final result = isEmpty ? 1 : 0;
        memo[key] = result;
        return result;
      } catch (_) {
        memo[key] = 0;
        return 0;
      }
    }

    inProgress[key] = true;
    int totalCount = _countAlternatives(rule.body(), input, start, end, memo, inProgress);
    inProgress[key] = false;
    memo[key] = totalCount;
    return totalCount;
  }

  int _countAlternatives(Pattern pattern, String input, int start, int end, Map<String, int> memo,
      Map<String, bool> inProgress) {
    if (pattern is Token) {
      if (start + 1 == end && pattern.match(input.codeUnitAt(start))) {
        return 1;
      }
      return 0;
    }

    if (pattern is Eps) {
      return start == end ? 1 : 0;
    }

    if (pattern is Marker) {
      return _countAlternatives(Eps(), input, start, end, memo, inProgress);
    }

    if (pattern is Alt) {
      return _countAlternatives(pattern.left, input, start, end, memo, inProgress) +
          _countAlternatives(pattern.right, input, start, end, memo, inProgress);
    }

    if (pattern is Seq) {
      int totalCount = 0;
      // Try all split points
      for (int mid = start; mid <= end; mid++) {
        final leftCount = _countAlternatives(pattern.left, input, start, mid, memo, inProgress);
        if (leftCount > 0) {
          final rightCount = _countAlternatives(pattern.right, input, mid, end, memo, inProgress);
          totalCount += leftCount * rightCount;
        }
      }
      return totalCount;
    }

    if (pattern is Plus) {
      // At least one match
      int totalCount = 0;
      for (int mid = start + 1; mid <= end; mid++) {
        final childCount = _countAlternatives(pattern.child, input, start, mid, memo, inProgress);
        if (childCount > 0) {
          final starCount = _countStar(pattern.child, input, mid, end, memo, inProgress);
          totalCount += childCount * starCount;
        }
      }
      return totalCount;
    }

    if (pattern is Call) {
      return _countDerivations(pattern.rule, input, start, end, memo, inProgress);
    }

    if (pattern is RuleCall) {
      return _countDerivations(pattern.rule, input, start, end, memo, inProgress);
    }

    if (pattern is Action) {
      // Action wraps another pattern - just delegate to unwrapped pattern
      return _countAlternatives(pattern.child, input, start, end, memo, inProgress);
    }

    if (pattern is Star) {
      return _countStar(pattern.child, input, start, end, memo, inProgress);
    }

    if (pattern is Conj) {
      if (start + 1 == end &&
          pattern.left.match(input.codeUnitAt(start)) &&
          pattern.right.match(input.codeUnitAt(start))) {
        return 1;
      }
      return 0;
    }

    if (pattern is PrecedenceLabeledPattern) {
      return _countAlternatives(pattern.pattern, input, start, end, memo, inProgress);
    }

    if (pattern is And || pattern is Not) {
      if (start == end &&
          _checkPredicatePattern(
                  pattern is And ? pattern.pattern : (pattern as Not).pattern, start) ==
              (pattern is And)) {
        return 1;
      }
      return 0;
    }

    return 0;
  }

  // Count zero or more matches of a pattern
  int _countStar(Pattern pattern, String input, int start, int end, Map<String, int> memo,
      Map<String, bool> inProgress) {
    if (start == end) {
      return 1; // Zero matches
    }

    int totalCount = 1; // Zero matches at current position

    // One or more matches
    for (int mid = start + 1; mid <= end; mid++) {
      final childCount = _countAlternatives(pattern, input, start, mid, memo, inProgress);
      if (childCount > 0) {
        final restCount = _countStar(pattern, input, mid, end, memo, inProgress);
        totalCount += childCount * restCount;
      }
    }

    return totalCount;
  }

  Iterable<ParseDerivation> _enumerateDerivations(
    Rule rule,
    String input,
    int start,
    int end,
    Map<String, List<ParseDerivation>?> memo,
    Map<String, bool> inProgress,
  ) sync* {
    final key = '${rule.name}:$start:$end';

    // If we've already computed this span, replay from cache
    if (memo.containsKey(key)) {
      yield* memo[key] ?? const [];
      return;
    }

    // Cycle guard — identity rules like Call(s) at the same span return nothing
    if (inProgress[key] == true) return;

    if (start == end) {
      try {
        if (rule.body().empty()) {
          final d = ParseDerivation(rule.symbolId!, start, end, []);
          memo[key] = [d];
          yield d;
        } else {
          memo[key] = [];
        }
      } catch (_) {
        memo[key] = [];
      }
      return;
    }

    inProgress[key] = true;
    final cache = <ParseDerivation>[];
    for (final d in _enumerateAlternatives(rule.body(), input, start, end, memo, inProgress)) {
      cache.add(d);
      yield d;
    }
    inProgress[key] = false;
    memo[key] = cache;
  }

  Iterable<ParseDerivation> _enumerateAlternatives(
    Pattern pattern,
    String input,
    int start,
    int end,
    Map<String, List<ParseDerivation>?> memo,
    Map<String, bool> inProgress,
  ) sync* {
    if (pattern is Token) {
      if (start + 1 == end && pattern.match(input.codeUnitAt(start))) {
        yield ParseDerivation(pattern.symbolId!, start, end, []);
      }
      return;
    }

    if (pattern is Eps) {
      if (start == end) yield ParseDerivation(pattern.symbolId, start, end, []);
      return;
    }

    if (pattern is Marker) {
      if (start == end) yield ParseDerivation(pattern.symbolId!, start, end, []);
      return;
    }

    if (pattern is Alt) {
      yield* _enumerateAlternatives(pattern.left, input, start, end, memo, inProgress);
      yield* _enumerateAlternatives(pattern.right, input, start, end, memo, inProgress);
      return;
    }

    if (pattern is Seq) {
      // CFG sequence: enumerate ALL splits where both left and right match
      for (int mid = start; mid <= end; mid++) {
        final leftList =
            _enumerateAlternatives(pattern.left, input, start, mid, memo, inProgress).toList();
        if (leftList.isEmpty) continue;

        final rightList =
            _enumerateAlternatives(pattern.right, input, mid, end, memo, inProgress).toList();
        if (rightList.isEmpty) continue;

        for (final left in leftList) {
          for (final right in rightList) {
            yield ParseDerivation(pattern.symbolId!, start, end, [left, right]);
          }
        }
      }
      return;
    }

    if (pattern is Plus) {
      for (int mid = start + 1; mid <= end; mid++) {
        final childList =
            _enumerateAlternatives(pattern.child, input, start, mid, memo, inProgress).toList();
        if (childList.isEmpty) continue;
        for (final child in childList) {
          for (final star in _enumerateStar(
              pattern.child, input, mid, end, '${pattern.child}*', memo, inProgress)) {
            // Only yield if plus covers the full requested span
            if (star.end == end) {
              yield ParseDerivation(pattern.symbolId!, start, end, [child, star]);
            }
          }
        }
      }
      return;
    }

    if (pattern is Call) {
      yield* _enumerateDerivations(pattern.rule, input, start, end, memo, inProgress);
      return;
    }

    if (pattern is RuleCall) {
      yield* _enumerateDerivations(pattern.rule, input, start, end, memo, inProgress);
      return;
    }

    if (pattern is Action) {
      for (final child
          in _enumerateAlternatives(pattern.child, input, start, end, memo, inProgress)) {
        yield ParseDerivation(pattern.symbolId!, start, end, [child]);
      }
      // yield* _enumerateAlternatives(pattern.child, input, start, end, memo, inProgress);
      return;
    }

    if (pattern is And) {
      // Positive lookahead: check if pattern matches at start position without consuming
      if (_checkPredicatePattern(pattern.pattern, start)) {
        // Predicate succeeded - yield empty derivation (zero-width match)
        yield ParseDerivation(pattern.symbolId!, start, start, []);
      }
      return;
    }

    if (pattern is Not) {
      // Negative lookahead: check if pattern does NOT match at start position
      if (!_checkPredicatePattern(pattern.pattern, start)) {
        // Predicate succeeded - yield empty derivation (zero-width match)
        yield ParseDerivation(pattern.symbolId!, start, start, []);
      }
      return;
    }

    if (pattern is Star) {
      yield* _enumerateStar(pattern.child, input, start, end, 'Star', memo, inProgress);
      return;
    }

    if (pattern is Conj) {
      if (start + 1 == end &&
          pattern.left.match(input.codeUnitAt(start)) &&
          pattern.right.match(input.codeUnitAt(start))) {
        yield ParseDerivation(pattern.symbolId!, start, end, []);
      }
      return;
    }

    if (pattern is PrecedenceLabeledPattern) {
      yield* _enumerateAlternatives(pattern.pattern, input, start, end, memo, inProgress);
      return;
    }
  }

  Iterable<ParseDerivation> _enumerateStar(
    Pattern pattern,
    String input,
    int start,
    int end,
    String symbol,
    Map<String, List<ParseDerivation>?> memo,
    Map<String, bool> inProgress,
  ) sync* {
    if (start == end) {
      yield ParseDerivation(pattern.symbolId!, start, end, []);
      return;
    }

    // PEG greedy matching: try longest match first
    for (int mid = end; mid > start; mid--) {
      final childList =
          _enumerateAlternatives(pattern, input, start, mid, memo, inProgress).toList();
      if (childList.isNotEmpty) {
        for (final child in childList) {
          for (final star in _enumerateStar(pattern, input, mid, end, symbol, memo, inProgress)) {
            // Use the actual end position from the star tree, not the requested 'end'
            final actualEnd = star.end;
            yield ParseDerivation(pattern.symbolId!, start, actualEnd, [child, star]);
          }
        }
        return; // Only use the first (longest) match - PEG greedy semantics
      }
    }

    // No match found - zero matches
    yield ParseDerivation(pattern.symbolId!, start, start, []);
  }

  /// Evaluate a [ParseDerivation] with evaluated semantic values.
  Object? evaluateParseDerivation(
    ParseDerivation derivation,
    String input,
  ) {
    return _evaluateParseDerivation(derivation, input);
  }

  /// Directly evaluate a [ParseTree] extracted from the forest.
  Object? evaluateParseTree(ParseTree tree, String input) {
    return _evaluateParseDerivation(
      parseTreeToDerivation(tree, input),
      input,
    );
  }

  Object? _evaluateParseDerivation(ParseDerivation tree, String input) {
    switch (grammar.symbolRegistry[tree.symbol]) {
      case Token pattern:
        if (tree.start + 1 == tree.end && pattern.match(input.codeUnitAt(tree.start))) {
          final evaluated = tree.getMatchedText(input);
          return evaluated;
        }
      case Marker pattern:
        return NamedMark(pattern.name, tree.start);
      case Eps():
        return "";
      case Alt():
        // One of the alternatives matched - evaluate that child
        if (tree.children.isNotEmpty) {
          return _evaluateParseDerivation(tree.children[0], input);
        }
        return null;
      case Seq():
        // Sequence: evaluate left and right children
        final results = <dynamic>[];
        for (final child in tree.children) {
          final childValue = _evaluateParseDerivation(child, input);
          results.add(childValue);
        }
        return results;
      case Conj():
        // Conjunction: both patterns match the same token
        final codeUnit = input.codeUnitAt(tree.start);
        return String.fromCharCode(codeUnit);
      case Plus():
      case Star():
        // One/Zero or more: collect all child results into a list.
        // We avoid flattening sequences (lists) from the body match.
        final results = <dynamic>[];
        if (tree.children.isNotEmpty) {
          // First child is the 'head' element
          results.add(_evaluateParseDerivation(tree.children[0], input));
          // Second child (if any) is the rest of the repetition (tail)
          if (tree.children.length > 1) {
            final rest = _evaluateParseDerivation(tree.children[1], input);
            if (rest is List) {
              results.addAll(rest);
            } else if (rest != "") {
              results.add(rest);
            }
          }
        }
        return results;
      case And():
        // Positive lookahead: zero-width, return empty list
        return [];
      case Not():
        // Negative lookahead: zero-width, return empty list
        return [];
      case Rule():
        // Evaluate the rule's body
        return _evaluateParseDerivation(
          tree.children.isNotEmpty
              ? tree.children[0]
              : ParseDerivation(Eps().symbolId, tree.start, tree.end, []),
          input,
        );
      case RuleCall _:
        // Recursively evaluate the referenced rule
        if (tree.children.isNotEmpty) {
          return _evaluateParseDerivation(tree.children[0], input);
        }
        return null;
      case Call _:
        // Recursively evaluate the referenced rule
        if (tree.children.isNotEmpty) {
          return _evaluateParseDerivation(tree.children[0], input);
        }
        return null;
      case Action<dynamic> action:
        // Evaluate the child and apply the semantic action
        assert(tree.children.length == 1, "Action Nodes should only have one child.");

        final childResults = <dynamic>[];
        for (final child in tree.children) {
          final childValue = _evaluateParseDerivation(child, input);
          childResults.add(childValue);
        }
        final span = tree.getMatchedText(input);
        if (childResults.length == 1 && childResults.single is List) {
          return action.callback(span, childResults.single);
        }
        return action.callback(span, childResults);
      case PrecedenceLabeledPattern():
        // Unwrap and evaluate the child pattern
        if (tree.children.isNotEmpty) {
          return _evaluateParseDerivation(tree.children[0], input);
        }
        return null;
      case null:
        throw StateError("Tried to evaluate using an invalid symbol.");
    }

    return null;
  }

  Step _processToken(
    int? token,
    int position,
    List<Frame> frames, {
    String input = '',
    BsrSet? bsr,
    bool isSavingMarks = true,
  }) {
    final step = Step(
      this,
      token,
      position,
      input: input,
      bsr: bsr,
      buffer: _predicateBuffer,
    );

    for (final frame in frames) {
      step._processFrame(frame);
    }

    return step;
  }

  /// Check if a pattern matches at a given position in the input without consuming.
  /// Used for AND/NOT lookahead predicates.
  ///
  /// This is a fast check that determines if a pattern would match at startPos
  /// without actually advancing the parser state.
  bool checkPatternAtPosition(Pattern pattern, String inputStr, int startPos) {
    _predicateBuffer.initializeFromString(inputStr);
    return _checkPredicatePattern(pattern, startPos);
  }

  /// Internal: recursive predicate pattern checking (uses buffer stored on parser)
  bool _checkPredicatePattern(Pattern pattern, int startPos) {
    // Base cases
    if (pattern is Token) {
      final codeUnit = _predicateBuffer.codeUnitAt(startPos);
      if (codeUnit >= 0) {
        return pattern.match(codeUnit);
      }
      return false;
    }

    if (pattern is Eps) {
      return true;
    }

    if (pattern is Marker) {
      return true;
    }

    if (pattern is Alt) {
      return _checkPredicatePattern(pattern.left, startPos) ||
          _checkPredicatePattern(pattern.right, startPos);
    }

    if (pattern is Seq) {
      return _checkPredicateSeq(pattern.left, pattern.right, startPos);
    }

    if (pattern is Plus) {
      return _checkPredicatePattern(pattern.child, startPos);
    }

    if (pattern is And) {
      return _checkPredicatePattern(pattern.pattern, startPos);
    }

    if (pattern is Not) {
      return !_checkPredicatePattern(pattern.pattern, startPos);
    }

    if (pattern is Call || pattern is RuleCall) {
      Rule rule = pattern is Call ? pattern.rule : (pattern as RuleCall).rule;
      return _ruleMatchesAtPosition(rule, startPos);
    }

    if (pattern is Action) {
      return _checkPredicatePattern(pattern.child, startPos);
    }

    // Default: assume matches
    return true;
  }

  /// Check if a sequence matches: left followed by right
  bool _checkPredicateSeq(Pattern left, Pattern right, int startPos) {
    // Determine how much 'left' consumes
    final leftLen = _estimatePatternLength(left, startPos);
    if (leftLen < 0) return false;
    return _checkPredicatePattern(right, startPos + leftLen);
  }

  /// Estimate how many characters a pattern would match.
  /// Returns >= 0 if matches, < 0 if doesn't match.
  int _estimatePatternLength(Pattern pattern, int startPos) {
    if (startPos > _predicateBuffer.length) return -1;

    if (pattern is Token) {
      if (_checkPredicatePattern(pattern, startPos)) {
        return 1;
      }
      return -1;
    }

    if (pattern is Eps) {
      return 0;
    }

    if (pattern is Marker) {
      return 0;
    }

    if (pattern is Alt) {
      int leftLen = _estimatePatternLength(pattern.left, startPos);
      if (leftLen >= 0) return leftLen;
      return _estimatePatternLength(pattern.right, startPos);
    }

    if (pattern is Plus) {
      return _estimatePatternLength(pattern.child, startPos);
    }

    if (pattern is And || pattern is Not) {
      // Predicates are zero-width
      return 0;
    }

    if (pattern is Call || pattern is RuleCall) {
      // For rules, we don't know the length - be conservative
      // A better implementation would parse to determine length
      return 0;
    }

    if (pattern is Action) {
      return _estimatePatternLength(pattern.child, startPos);
    }

    // Default: unknown
    return -1;
  }

  /// Check if a rule's body matches at the given position
  bool _ruleMatchesAtPosition(Rule rule, int startPos) {
    if (startPos >= _predicateBuffer.length && !rule.body().empty()) {
      return false;
    }

    // Check if the rule body can match from startPos to any end position
    try {
      // Try to find at least one valid match
      for (int endPos = startPos; endPos <= _predicateBuffer.length; endPos++) {
        if (_patternCanMatch(rule.body(), startPos, endPos)) {
          return true;
        }
      }
      return false;
    } catch (_) {
      // If anything goes wrong, be conservative
      return true;
    }
  }

  /// Check if a pattern can match the span [start, end)
  bool _patternCanMatch(Pattern pattern, int start, int end) {
    if (pattern is Token) {
      return start + 1 == end && pattern.match(_predicateBuffer.codeUnitAt(start));
    }

    if (pattern is Eps) {
      return start == end;
    }

    if (pattern is Marker) {
      return start == end;
    }

    if (pattern is Alt) {
      return _patternCanMatch(pattern.left, start, end) ||
          _patternCanMatch(pattern.right, start, end);
    }

    if (pattern is Seq) {
      // Try all split points
      for (int mid = start; mid <= end; mid++) {
        if (_patternCanMatch(pattern.left, start, mid) &&
            _patternCanMatch(pattern.right, mid, end)) {
          return true;
        }
      }
      return false;
    }

    if (pattern is Plus) {
      // At least one match
      if (start == end) return false;
      for (int mid = start + 1; mid <= end; mid++) {
        if (_patternCanMatch(pattern.child, start, mid)) {
          // Check if rest can be matched by zero or more
          if (mid == end || _patternCanMatchStar(pattern.child, mid, end)) {
            return true;
          }
        }
      }
      return false;
    }

    if (pattern is And || pattern is Not) {
      return start == end;
    }

    if (pattern is Call || pattern is RuleCall) {
      Rule rule = pattern is Call ? pattern.rule : (pattern as RuleCall).rule;
      return _patternCanMatch(rule.body(), start, end);
    }

    if (pattern is Action) {
      return _patternCanMatch(pattern.child, start, end);
    }

    return false;
  }

  /// Check if a pattern can match zero or more times in the span [start, end)
  bool _patternCanMatchStar(Pattern pattern, int start, int end) {
    if (start == end) return true; // Zero matches

    // Try one match
    for (int mid = start + 1; mid <= end; mid++) {
      if (_patternCanMatch(pattern, start, mid) && _patternCanMatchStar(pattern, mid, end)) {
        return true;
      }
    }

    return false;
  }
}

// ---------------------------------------------------------------------------
// Internal parsing machinery
// ---------------------------------------------------------------------------

/// Strongly typed key to identify a call site.
sealed class CallerKey {
  const CallerKey();
}

/// Represents the root call context.
final class RootCallerKey extends CallerKey {
  const RootCallerKey();

  @override
  int get hashCode => 0;

  @override
  bool operator ==(Object other) => other is RootCallerKey;
}

/// Caller tracking for rule returns
final class Caller extends CallerKey {
  /// Key is a (caller, nextState) pair encoded as a two-element list.
  final Map<(CallerKey, State), List<GlushList<Mark>?>> _grouped = {};

  /// The input position at which the associated rule was invoked.
  /// Set once at CallAction time; used by ReturnAction to record BSR entries.
  int? callStart;

  void addReturn(Context context, State nextState) {
    final key = (context.caller, nextState);
    _grouped.putIfAbsent(key, () => []).add(context.marks);
  }

  void forEach(void Function(CallerKey, State, GlushList<Mark>?) callback) {
    for (final MapEntry(key: (caller, nextState), value: marks) in _grouped.entries) {
      for (final mark in marks) {
        callback(caller, nextState, mark);
      }
    }
  }
}

/// Context for parsing (tracks marks, callers, and BSR call-start position).
class Context {
  final CallerKey caller;
  final GlushList<Mark>? marks;

  /// The input position at which the rule associated with this context
  /// was invoked.  Used to record BSR rule-completion entries.
  final int? callStart;

  /// The computed semantic value at this point in parsing.
  /// Updated as semantic actions are evaluated during parsing.
  final Object? semanticValue;

  const Context(this.caller, this.marks, [this.callStart, this.semanticValue]);
}

/// Frame for managing parsing states
class Frame {
  final Context context;
  final Set<State> nextStates;

  Frame(this.context) : nextStates = {};

  Frame copy() => Frame(context);

  CallerKey get caller => context.caller;
  GlushList<Mark>? get marks => context.marks;
}

/// Single step in parsing
class Step {
  final SMParser parser;
  final int? token;
  final int position;
  final String input;

  /// Optional BSR set to populate with rule-completion entries. When null,
  /// BSR recording is skipped (used by the plain recognize/parse paths).
  final BsrSet? bsr;

  /// Predicate lookahead buffer for checking patterns without full input access
  final PredicateLookaheadBuffer buffer;

  final List<Frame> nextFrames = [];
  final Map<Rule, Caller> _callers = {};
  final Set<CallerKey> _returnedCallers = {};
  final List<Context> _acceptedContexts = [];

  /// Frames created during CPS processing that need conditional adding to nextFrames
  final Set<Frame> _localFramesInCurrentProcessing = {};

  Step(
    this.parser,
    this.token,
    this.position, {
    required this.input,
    this.bsr,
    required this.buffer,
  });

  bool get accept => _acceptedContexts.isNotEmpty;

  List<Mark> get marks {
    final markList = _acceptedContexts[0].marks;
    if (markList == null) return [];
    return markList.toList().cast<Mark>();
  }

  /// Work queue for CPS trampoline - stores frame/state pairs to process
  late final DoubleLinkedQueue<_ProcessWork> _workQueue = DoubleLinkedQueue<_ProcessWork>();

  /// Create a local frame that will be conditionally added to nextFrames if it has states
  Frame _createLocalFrame(Context context) {
    final frame = Frame(context);
    _localFramesInCurrentProcessing.add(frame);
    return frame;
  }

  /// Enqueue work to process a frame/state pair (CPS continuation)
  void _enqueueProcess(Frame frame, State state) {
    _workQueue.add(_ProcessWork(frame, state));
  }

  /// CPS-style processing: instead of recursive _process calls, we handle with a trampoline
  void _processWork(Frame frame, State state) {
    for (final action in state.actions) {
      switch (action) {
        case SemanticAction():
          // Evaluate semantic action during parsing
          // Extract child results from marks (StringMark values)
          final marks = frame.marks?.toList() ?? [];
          final childResults = <Object?>[];
          int spanStart = position;
          int spanEnd = position;

          for (final mark in marks) {
            if (mark is StringMark) {
              childResults.add(mark.value);
              spanStart = spanStart > mark.position ? mark.position : spanStart;
              spanEnd = mark.position + 1; // Update end position
            } else if (mark is NamedMark) {
              spanStart = spanStart > mark.position ? mark.position : spanStart;
              spanEnd = spanEnd < mark.position ? mark.position : spanEnd;
            }
          }

          // Compute the span string from input
          final span = spanStart < input.length && spanEnd <= input.length
              ? input.substring(spanStart, spanEnd)
              : '';

          // Call the semantic action callback with computed span and child results
          final computedValue = action.callback(span, childResults);

          // Create new context with computed semantic value
          final semanticCtx = Context(
            frame.caller,
            frame.marks,
            frame.context.callStart,
            computedValue,
          );
          final nextFrame = _createLocalFrame(semanticCtx);
          _enqueueProcess(nextFrame, action.nextState);
        case TokenAction():
          if (token case var token? when action.pattern.match(token)) {
            // If token matches, add a StringMark with the captured token if not ExactToken
            // So ranges and 'any' tokens are captured into the marks array too
            var newMarks = frame.marks;
            if (action.pattern case Token(:var choice) when choice is! ExactToken) {
              final strMark = StringMark(String.fromCharCode(token), position);
              newMarks = (newMarks ?? const GlushList.empty()).add(strMark);
            }
            final nextFrame = Frame(Context(frame.caller, newMarks));
            nextFrame.nextStates.add(action.nextState);
            nextFrames.add(nextFrame);
            // TokenAction does NOT enqueue - it defers to next token step
          }
        case MarkAction():
          final mark = NamedMark(action.name, position);
          final markCtx = Context(
            frame.caller,
            (frame.marks ?? const GlushList.empty()).add(mark),
          );
          // Create local frame that will be conditionally added to nextFrames
          final markFrame = _createLocalFrame(markCtx);
          // Enqueue instead of _withFrame callback
          _enqueueProcess(markFrame, action.nextState);
        case PredicateAction():
          // Predicate checking (lookahead without consumption)
          // Buffer ensures we have the data needed for lookahead
          bool predicateMatches = parser._checkPredicatePattern(action.pattern, position);

          // For AND (&pattern), continue if pattern matches
          // For NOT (!pattern), continue if pattern does NOT match
          final shouldContinue = action.isAnd ? predicateMatches : !predicateMatches;

          if (shouldContinue) {
            // Predicate succeeded - enqueue next state processing
            // Zero-width: processed with the same token in this frame step
            final predFrame = _createLocalFrame(frame.context);
            _enqueueProcess(predFrame, action.nextState);
          }
        // If predicate failed, we simply don't enqueue (backtrack)
        case CallAction():
          final rule = action.rule;
          final isExecuted = _callers.containsKey(rule);
          final caller = _callers.putIfAbsent(rule, Caller.new);

          caller.addReturn(frame.context, action.returnState);
          if (!isExecuted) {
            // Store callStart on the Caller so ReturnAction can emit BSR entries.
            caller.callStart = position;
            final callCtx = Context(caller, const GlushList.empty(), position);
            // Create local frame that will be conditionally added to nextFrames
            final callFrame = _createLocalFrame(callCtx);
            // Enqueue first states instead of _withFrame callback
            for (final firstState in parser.stateMachine.ruleFirst[rule] ?? []) {
              _enqueueProcess(callFrame, firstState);
            }
          }
        case ReturnAction():
          final rule = action.rule;

          if (token != null && rule.guard != null && !rule.guard!.match(token)) {
            continue;
          }

          // Record BSR rule-completion entry BEFORE the ambiguity guard,
          // so every distinct (rule, callStart, position) span is captured.
          // The _returnedCallers guard below is only for parsing-state correctness.
          final callStart = frame.context.callStart ??
              (frame.caller is Caller //
                  ? (frame.caller as Caller).callStart
                  : null);
          if ((bsr, callStart) case (var bsr?, var callStart?)) {
            bsr.add(rule, callStart, position);
          }

          final caller = frame.caller;

          // Simple ambiguity handling: only process each caller once
          final shouldProcess = _returnedCallers.add(caller);
          if (!shouldProcess) continue;

          if (caller is Caller) {
            caller.forEach((ccaller, nextState, marks) {
              final nextMarks = marks == null
                  ? frame.marks
                  : GlushList.branched<Mark>([marks])
                      .addList(frame.marks ?? const GlushList.empty());

              final nextContext = Context(ccaller, nextMarks);
              // Create local frame that will be conditionally added to nextFrames
              final nextFrame = _createLocalFrame(nextContext);
              // Enqueue instead of _withFrame callback
              _enqueueProcess(nextFrame, nextState);
            });
          }
        case AcceptAction():
          _acceptedContexts.add(frame.context);
      }
    }
  }

  void _processFrame(Frame frame) {
    _workQueue.clear();
    _localFramesInCurrentProcessing.clear();
    final nextFrame = Frame(frame.copy().context);

    // Initialize work queue with all states from the frame
    for (final state in frame.nextStates) {
      _enqueueProcess(nextFrame, state);
    }

    // Trampoline loop: process all enqueued work iteratively
    while (_workQueue.isNotEmpty) {
      final work = _workQueue.removeFirst();
      _processWork(work.frame, work.state);
    }

    // After all work is done, add frames that have states to nextFrames
    // Local frames (created within _processWork) are only added if they have states
    for (final localFrame in _localFramesInCurrentProcessing) {
      if (localFrame.nextStates.isNotEmpty) {
        nextFrames.add(localFrame);
      }
    }

    // Add the main nextFrame if it has states
    if (nextFrame.nextStates.isNotEmpty) {
      nextFrames.add(nextFrame);
    }
  }
}

/// Work item for CPS trampoline - represents the continuation to process a frame/state pair
class _ProcessWork {
  final Frame frame;
  final State state;

  _ProcessWork(this.frame, this.state);
}


''';
